self.addEventListener("push",t=>{let i={};if(t.data)try{i=t.data.json()}catch{i={title:t.data.text()}}t.waitUntil(self.registration.showNotification(i.title??"Fairshare",{body:i.body??"",icon:"/icon.png",badge:"/icon.png",data:{url:i.url??"/dashboard"}}))}),self.addEventListener("notificationclick",t=>{t.notification.close();let i=new URL(t.notification.data?.url??"/dashboard",self.location.origin).href;t.waitUntil(clients.matchAll({type:"window",includeUncontrolled:!0}).then(t=>{let n=t.find(t=>t.url===i);if(n)return n.focus();let e=t[0];return e?e.navigate(i).then(t=>t?.focus()):clients.openWindow(i)}))});